          "wait": {
            "type": "boolean",
            "description": "If true, wait for the agent to complete before returning. If false (default), return immediately with current status."
          },
          "timeout": {
            "type": "number",
            "description": "Maximum time in seconds to wait if wait is true. Default is 30, maximum is 180."
          },
          "since_turn": {
            "type": "number",
            "description": "If provided, only return turn responses after this index (exclusive). For example, since_turn: 0 returns turns 1, 2, ... Use the last turn_index from a previous read to get only new responses."
